const DRAGON_MATERIAL = "dragon";

export function processClaim(
  policy: Policy,
  damages: Damage[],
): { payout: number; remainingCap: number } {
  // Validate negative amounts
  for (const dmg of damages) {
    if (dmg.amount < 0) {
      throw new Error(`Negative damage amount: ${dmg.amount}`);
    }
  }

  // Validate: damages by type must not exceed items of that type in policy
  const policyTypeCounts = new Map<string, number>();
  for (const item of policy.items) {
    policyTypeCounts.set(item.type, (policyTypeCounts.get(item.type) ?? 0) + 1);
  }
