  for (const dmg of damages) {
    damageTypeCounts.set(dmg.itemType, (damageTypeCounts.get(dmg.itemType) ?? 0) + 1);
  }
  for (const [type, count] of damageTypeCounts) {
    const policyCount = policyTypeCounts.get(type) ?? 0;
    if (policyCount === 0) {
      throw new Error(`Damage references item type not in policy: ${type}`);
    }
    if (count > policyCount) {
      throw new Error(
        `Damage references more items of type ${type} than policy covers`,
      );
    }
  }

  // Match damages to items by type (in order).
  const itemsByType = new Map<string, Item[]>();
  for (const item of policy.items) {
    const list = itemsByType.get(item.type) ?? [];
    list.push(item);
    itemsByType.set(item.type, list);
  }

  const usageIndex = new Map<string, number>();
  let totalPayoutRaw = 0;

  for (const dmg of damages) {
    const items = itemsByType.get(dmg.itemType)!;
    const idx = usageIndex.get(dmg.itemType) ?? 0;
    const item = items[idx];
    usageIndex.set(dmg.itemType, idx + 1);

    let payout: number;
    const isDragon = item.material === DRAGON_MATERIAL;
    const isHighEnch =
      item.enchantment !== undefined && item.enchantment >= HIGH_ENCH_PAYOUT_THRESHOLD;

    if (isHighEnch) {
      // High enchantment clause wins (50%) even over dragon material
      payout = dmg.amount * HIGH_ENCH_PAYOUT_FACTOR;
    } else if (isDragon) {
      payout = dmg.amount;
    } else {
      payout = dmg.amount;
    }

    // Apply deductible per damage event
    payout = payout - DEDUCTIBLE;
    if (payout < 0) payout = 0;

    totalPayoutRaw += payout;
  }

  // Apply cap
  let finalPayout = totalPayoutRaw;
  if (finalPayout > policy.remainingCap) {
    finalPayout = policy.remainingCap;
  }

  // Round down (in MHPCO's favor for payouts)
  finalPayout = Math.floor(finalPayout);

  const remaining = policy.remainingCap - finalPayout;

  return { payout: finalPayout, remainingCap: remaining };
}

