import { processClaim } from "./claim.js";
import { computePremium, getInsuranceSum, isKnownItem } from "./quote.js";
import {
  ClaimResult,
  Output,
  Policy,
  QuoteResult,
  Scenario,
  StepResult,
} from "./types.js";

export function runScenario(scenario: Scenario): Output {
  const results: StepResult[] = [];
  const policies = new Map<number, Policy>();
  let quoteCount = 0;

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === "quote") {
      // Validate items
      for (const item of step.items) {
        if (!isKnownItem(item)) {
          throw new Error(`Unknown item type in quote: ${item.type}`);
        }
      }
      const isFollowUp = quoteCount > 0;
      const premium = computePremium(step.items, scenario.customer, isFollowUp);
      const insuranceSum = getInsuranceSum(step.items);
      const policy: Policy = {
        items: step.items,
        insuranceSum,
        remainingCap: 2 * insuranceSum,
      };
      policies.set(i, policy);
      quoteCount += 1;
      const result: QuoteResult = { premium };
      results.push(result);
    } else {
      const policy = policies.get(step.policy);
      if (!policy) {
        throw new Error(`Claim references unknown policy: ${step.policy}`);
      }
      const r = processClaim(policy, step.incident.damages);
      policy.remainingCap = r.remainingCap;
      const result: ClaimResult = { payout: r.payout, remainingCap: r.remainingCap };
      results.push(result);
    }
  }

  return { results };
}

