        {
          op: "claim",
          policy: 0,
          incident: {
            cause: "x",
            damages: [{ itemType: "sword", amount: 1000 }],
          },
        },
      ],
    });
    expect((r.results[1] as any).payout).toBe(400);
  });
});

describe("Deductible per damage event", () => {
  it("dragon attack damages sword (500) and amulet (300) → payout 600 G", () => {
