import { Customer, Item } from "./types.js";

const MAIN_ITEMS: Record<string, { value: number; premium: number }> = {
  sword: { value: 1000, premium: 100 },
  amulet: { value: 600, premium: 60 },
  staff: { value: 800, premium: 80 },
  potion: { value: 400, premium: 40 },
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const COMPONENT_VALUE = 250;
const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

const PROCESSING_FEE = 5;
const CURSE_SURCHARGE = 0.5;
const HIGH_ENCH_SURCHARGE = 0.3;
const HIGH_ENCH_THRESHOLD = 5;
const LOYALTY_DISCOUNT = 0.2;
const LOYALTY_YEARS = 2;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const FOLLOWUP_DISCOUNT = 0.15;

export function isKnownItem(item: Item): boolean {
  return item.type in MAIN_ITEMS || COMPONENT_TYPES.has(item.type);
}

export function getInsuranceValue(item: Item): number {
  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].value;
  if (COMPONENT_TYPES.has(item.type)) return COMPONENT_VALUE;
  throw new Error(`Unknown item type: ${item.type}`);
}

export function getInsuranceSum(items: Item[]): number {
  return items.reduce((sum, item) => sum + getInsuranceValue(item), 0);
}

// Returns the per-item base premium with surcharges applied for that item.
// Components are returned as a sum after block discounting per type.
function computeItemBasePremiums(items: Item[]): number {
  // Separate main items and components.
  const mainItems = items.filter((i) => i.type in MAIN_ITEMS);
  const componentItems = items.filter((i) => COMPONENT_TYPES.has(i.type));

  let total = 0;

  for (const item of mainItems) {
    let base = MAIN_ITEMS[item.type].premium;
    let withItemSurcharges = base;
    if (item.cursed) withItemSurcharges += base * CURSE_SURCHARGE;
    if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCH_THRESHOLD) {
      withItemSurcharges += base * HIGH_ENCH_SURCHARGE;
    }
    total += withItemSurcharges;
  }

  // Group components by type and apply block discount per group.
  const componentsByType = new Map<string, Item[]>();
  for (const c of componentItems) {
    const list = componentsByType.get(c.type) ?? [];
    list.push(c);
    componentsByType.set(c.type, list);
  }

  for (const [, group] of componentsByType) {
    // Block applies only to exactly 3.
    if (group.length === COMPONENT_BLOCK_SIZE) {
      let groupTotal = COMPONENT_BLOCK_PREMIUM;
      // Components may also have cursed / enchantment, but spec doesn't say.
      // Treat surcharges similarly: applied to the per-component base 25 G,
      // but since the block discount changes the base, we apply surcharges
      // to each component's individual base 25 (conservative interpretation).
      for (const item of group) {
        const itemBase = COMPONENT_PREMIUM;
        if (item.cursed) groupTotal += itemBase * CURSE_SURCHARGE;
        if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCH_THRESHOLD) {
          groupTotal += itemBase * HIGH_ENCH_SURCHARGE;
        }
      }
      total += groupTotal;
    } else {
      for (const item of group) {
        let base = COMPONENT_PREMIUM;
        let withItemSurcharges = base;
        if (item.cursed) withItemSurcharges += base * CURSE_SURCHARGE;
        if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCH_THRESHOLD) {
          withItemSurcharges += base * HIGH_ENCH_SURCHARGE;
        }
        total += withItemSurcharges;
      }
    }
  }

  return total;
}

export function computePremium(
  items: Item[],
  customer: Customer,
  isFollowUpContract: boolean,
): number {
  // Validate items
  for (const item of items) {
    if (!isKnownItem(item)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  let premium = computeItemBasePremiums(items);

  // Policy-wide modifiers: loyalty, first insurance (per item), follow-up.
  // "First insurance" surcharge applies to each item (per spec integration
  // example: each item in a quote is treated as a first insurance).
  let firstInsuranceSurcharge = 0;
  for (const item of items) {
    let baseForFirst: number;
    if (item.type in MAIN_ITEMS) baseForFirst = MAIN_ITEMS[item.type].premium;
    else baseForFirst = COMPONENT_PREMIUM;
    firstInsuranceSurcharge += baseForFirst * FIRST_INSURANCE_SURCHARGE;
  }

  // Loyalty discount on policy base premium (sum of per-item bases without item-specific surcharges? Or after?)
  // Spec says "policy-wide modifiers apply to the policy base premium (the sum of all item base premiums)".
  // So loyalty/followup are computed on the raw sum of item base premiums (not the post-surcharge total).
  const policyBasePremium = computePolicyBasePremium(items);

  let loyaltyDiscount = 0;
  if (customer.yearsWithMHPCO >= LOYALTY_YEARS) {
    loyaltyDiscount = policyBasePremium * LOYALTY_DISCOUNT;
  }

  let followUpDiscount = 0;
  if (isFollowUpContract) {
    followUpDiscount = policyBasePremium * FOLLOWUP_DISCOUNT;
  }

  premium = premium + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount;

  // Processing fee
  premium += PROCESSING_FEE;

  // Round up (in MHPCO's favor for premiums)
  return Math.ceil(premium);
}

function computePolicyBasePremium(items: Item[]): number {
  const mainItems = items.filter((i) => i.type in MAIN_ITEMS);
  const componentItems = items.filter((i) => COMPONENT_TYPES.has(i.type));

  let total = 0;
  for (const item of mainItems) {
    total += MAIN_ITEMS[item.type].premium;
  }

  const componentsByType = new Map<string, Item[]>();
  for (const c of componentItems) {
    const list = componentsByType.get(c.type) ?? [];
    list.push(c);
    componentsByType.set(c.type, list);
  }

  for (const [, group] of componentsByType) {
    if (group.length === COMPONENT_BLOCK_SIZE) {
      total += COMPONENT_BLOCK_PREMIUM;
    } else {
      total += group.length * COMPONENT_PREMIUM;
    }
  }

  return total;
}

